import { BrowserRouter, Routes, Route, Outlet, Link, NavLink } from 'react-router-dom';

function Dashboard() {
  return (
    &lt;div style={{ display: 'flex' }}&gt;
      &lt;aside style={{ width: '250px', padding: '1rem' }}&gt;
        &lt;nav&gt;
          &lt;NavLink to="/dashboard" end&gt;Aperçu&lt;/NavLink&gt;
          &lt;NavLink to="/dashboard/cours"&gt;Mes cours&lt;/NavLink&gt;
          &lt;NavLink to="/dashboard/profil"&gt;Profil&lt;/NavLink&gt;
        &lt;/nav&gt;
      &lt;/aside&gt;
      &lt;main style={{ flex: 1 }}&gt;
        &lt;Outlet /&gt;
      &lt;/main&gt;
    &lt;/div&gt;
  );
}

function DashboardAccueil() { return &lt;div&gt;Statistiques...&lt;/div&gt;; }
function DashboardCours() { return &lt;div&gt;Liste des cours...&lt;/div&gt;; }
function DashboardProfil() { return &lt;div&gt;Profil...&lt;/div&gt;; }
function DashboardCoursDetail() { return &lt;div&gt;Détail cours...&lt;/div&gt;; }

function App() {
  return (
    &lt;BrowserRouter&gt;
      &lt;Routes&gt;
        &lt;Route path="/dashboard" element={&lt;Dashboard /&gt;}&gt;
          &lt;Route index element={&lt;DashboardAccueil /&gt;} /&gt;
          &lt;Route path="cours" element={&lt;DashboardCours /&gt;} /&gt;
          &lt;Route path="cours/:id" element={&lt;DashboardCoursDetail /&gt;} /&gt;
          &lt;Route path="profil" element={&lt;DashboardProfil /&gt;} /&gt;
        &lt;/Route&gt;
      &lt;/Routes&gt;
    &lt;/BrowserRouter&gt;
  );
}
```
Le composant Dashboard contient un `<Outlet />` qui est le point d'insertion des routes enfants. `index` correspond à l'URL exacte `/dashboard`.

